class Solution {
public:
    int countCharacters(vector<string>& words, string chars) {
        int res = 0;
        unordered_map<char, int> mp;
        for (char c : chars) {
            mp[c]++;
        }
        for (string word : words) {
            unordered_map<char, int> temp = mp;
            bool flag = true;
            for (char c : word) {
                if (temp[c]-- <= 0) {
                    flag = false;
                    break;
                }
            }
            if (flag) {
                res += word.size();
            }
        }
        return res;
    }
};
```
